import React, { useEffect, useState } from 'react';
import { useSelector, useDispatch } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { fetchMyGroups, fetchDiscoverGroups, deleteGroup, leaveGroup, joinGroup } from '../redux/thunks/groupThunks';
import { NODE_API } from '../api/config';
import { toast } from 'react-toastify';
import './Groups.css';

const Groups = () => {
  const [tab, setTab] = useState('my'); // my, discover
  const [showCreate, setShowCreate] = useState(false);
  const [newName, setNewName] = useState('');
  const [newDesc, setNewDesc] = useState('');
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const { user } = useSelector((state) => state.auth);
  const { myGroups, discoverGroups, loading } = useSelector((state) => state.groups);

  useEffect(() => {
    dispatch(fetchMyGroups());
    dispatch(fetchDiscoverGroups({ skip: 0, limit: 50 }));
  }, [dispatch]);

  const getImageUrl = (path) => {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    return `${NODE_API}/${path}`;
  };

  const getGroupIcon = (group) => {
    const icon = group?.ExtraElements?.groupIcon || group?.ExtraElements?.profileImage || group?.groupIcon;
    return getImageUrl(icon?.original || icon?.thumbnail || icon);
  };

  const getGroupId = (group) => group?._id || group?.groupId;
  const getGroupName = (group) => group?.groupName || group?.name || 'Group';
  const isAdmin = (group) => {
    const adminId = group?.groupAdminId || group?.groupAdmin || group?.admin;
    return adminId === user?._id;
  };

  const handleDelete = async (group) => {
    if (!window.confirm(`Delete "${getGroupName(group)}"?`)) return;
    const result = await dispatch(deleteGroup({ groupId: getGroupId(group) }));
    if (!result.error) {
      toast.success('Group deleted');
    } else {
      toast.error('Failed to delete group');
    }
  };

  const handleLeave = async (group) => {
    if (!window.confirm(`Leave "${getGroupName(group)}"?`)) return;
    const result = await dispatch(leaveGroup({ groupId: getGroupId(group) }));
    if (!result.error) {
      toast.success('Left group');
    } else {
      toast.error('Failed to leave group');
    }
  };

  const handleJoin = async (group) => {
    const result = await dispatch(joinGroup({ groupId: getGroupId(group) }));
    if (!result.error) {
      toast.success('Join request sent!');
      dispatch(fetchMyGroups());
    } else {
      toast.error('Failed to join group');
    }
  };

  const handleCreateGroup = () => {
    navigate('/groups/create');
  };

  const renderGroupCard = (group, actions) => {
    const icon = getGroupIcon(group);
    const name = getGroupName(group);
    const desc = group?.description || group?.groupDescription || '';
    const type = group?.type;

    return (
      <div
        key={getGroupId(group) || Math.random()}
        className="group-card"
      >
        <div className="group-card-left" onClick={() => navigate(`/groups/${getGroupId(group)}`)}>
          {icon ? (
            <img src={icon} alt="" className="group-icon" />
          ) : (
            <div className="group-icon-placeholder">👥</div>
          )}
          <div className="group-card-info">
            <span className="group-card-name">{name}</span>
            {desc && <span className="group-card-desc">{desc}</span>}
            {type === 'Private Group' && <span className="group-card-badge">Private</span>}
          </div>
        </div>
        <div className="group-card-actions">
          {actions}
        </div>
      </div>
    );
  };

  return (
    <div className="groups-page">
      {/* Header */}
      <div className="groups-header">
        <button className="groups-back-btn" onClick={() => navigate(-1)}>←</button>
        <h1 className="groups-title">Groups</h1>
        <div className="groups-header-btns">
          <button className="groups-join-btn" onClick={() => setTab('discover')}>
            Join Group
          </button>
          <button className="groups-create-btn" onClick={handleCreateGroup}>
            Create Group
          </button>
        </div>
      </div>

      {/* Tabs */}
      <div className="groups-tabs">
        <button className={`groups-tab ${tab === 'my' ? 'active' : ''}`} onClick={() => setTab('my')}>
          My Groups
        </button>
        <button className={`groups-tab ${tab === 'discover' ? 'active' : ''}`} onClick={() => setTab('discover')}>
          Discover
        </button>
      </div>

      {/* My Groups */}
      {tab === 'my' && (
        <div className="groups-list">
          {loading && myGroups.length === 0 && (
            <div className="groups-loading"><div className="page-loading-spinner" /></div>
          )}
          {!loading && myGroups.length === 0 && (
            <div className="groups-empty">
              <p>You haven't joined any groups yet</p>
              <button className="groups-empty-btn" onClick={() => setTab('discover')}>
                Discover Groups
              </button>
            </div>
          )}
          {myGroups.map((group) =>
            renderGroupCard(group, (
              <>
                {isAdmin(group) ? (
                  <button className="group-action-btn group-delete-btn" onClick={() => handleDelete(group)}>
                    🗑
                  </button>
                ) : (
                  <button className="group-action-btn group-leave-btn" onClick={() => handleLeave(group)}>
                    🚪
                  </button>
                )}
              </>
            ))
          )}
        </div>
      )}

      {/* Discover */}
      {tab === 'discover' && (
        <div className="groups-list">
          {discoverGroups.length === 0 && (
            <div className="groups-empty"><p>No groups to discover</p></div>
          )}
          {discoverGroups.map((group) =>
            renderGroupCard(group, (
              <button className="group-action-btn group-join-btn" onClick={() => handleJoin(group)}>
                ➕
              </button>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default Groups;
